const CONCEPTS = [
  {id:1,emoji:'📖',ar:{title:'القرآن منهج حياة',desc:'القرآن ليس كتاباً للتبرك فحسب، بل هو منهج حياة شامل. الغزالي يرى أن كثيراً من المسلمين يقرأون القرآن دون تدبر، فيحرمون أنفسهم من هدايته.',insight:'القرآن نزل ليُعمل به لا ليُتلى فقط',reflection:'كم مرة قرأت القرآن وتوقفت لتتأمل معانيه؟',action:'اقرأ صفحة واحدة بتدبر اليوم — توقف عند كل آية وتأمل معناها'},en:{title:'The Quran: A Way of Life',desc:'The Quran is not just a book for blessings but a comprehensive way of life. Al-Ghazali believes many Muslims read the Quran without reflection, depriving themselves of its guidance.',insight:'The Quran was revealed to be acted upon, not just recited',reflection:'How often do you read the Quran and pause to contemplate its meanings?',action:'Read one page with reflection today — pause at each verse and contemplate its meaning'},fr:{title:'Le Coran : Un Mode de Vie',desc:"Le Coran n'est pas seulement un livre de benedictions mais un mode de vie complet. Al-Ghazali croit que beaucoup de musulmans lisent le Coran sans reflexion.",insight:'Le Coran a ete revele pour etre mis en pratique, pas seulement recite',reflection:'Combien de fois lisez-vous le Coran en vous arretant pour reflechir ?',action:"Lisez une page avec reflexion aujourd'hui"}},
  {id:2,emoji:'🌟',ar:{title:'البلاغة القرآنية',desc:'القرآن تحدّى العرب — أمهر الناس في البلاغة — أن يأتوا بمثله فعجزوا. جمال اللغة القرآنية يفوق كل ما أنتجه البشر.',insight:'الإعجاز البلاغي هو الدليل الأول على أن القرآن من عند الله',reflection:'هل تأملت يوماً في جمال تعبير قرآني واحد؟',action:'اختر آية وتأمل في جمال تعبيرها اللغوي'},en:{title:'Quranic Eloquence',desc:"The Quran challenged the Arabs — the most skilled people in eloquence — to produce anything like it, and they failed. The beauty of Quranic language surpasses all human production.",insight:"Literary miracle is the first proof that the Quran is from God",reflection:'Have you ever contemplated the beauty of a single Quranic expression?',action:'Choose a verse and contemplate its linguistic beauty'},fr:{title:'L\'Eloquence Coranique',desc:"Le Coran a defie les Arabes — les plus habiles en eloquence — de produire quelque chose de semblable, et ils ont echoue.",insight:'Le miracle litteraire est la premiere preuve que le Coran vient de Dieu',reflection:"Avez-vous deja contemple la beaute d'une expression coranique ?",action:'Choisissez un verset et contemplez sa beaute linguistique'}},
  {id:3,emoji:'🔬',ar:{title:'الإشارات العلمية',desc:'القرآن يحتوي على إشارات علمية دقيقة عن الكون والإنسان والطبيعة، نزلت في زمن لم يكن العلم قد اكتشفها بعد.',insight:'الإشارات العلمية في القرآن دليل على مصدره الإلهي',reflection:'كم إشارة علمية في القرآن تعرفها؟',action:'ابحث عن إشارة علمية واحدة في القرآن وتعمق في فهمها'},en:{title:'Scientific Signs',desc:'The Quran contains precise scientific references about the universe, humans, and nature, revealed at a time when science had not yet discovered them.',insight:"Scientific signs in the Quran are evidence of its divine source",reflection:'How many scientific signs in the Quran do you know?',action:'Research one scientific sign in the Quran and deepen your understanding'},fr:{title:'Les Signes Scientifiques',desc:"Le Coran contient des references scientifiques precises sur l'univers, l'humain et la nature, revelees a une epoque ou la science ne les avait pas encore decouvertes.",insight:'Les signes scientifiques dans le Coran sont une preuve de sa source divine',reflection:'Combien de signes scientifiques dans le Coran connaissez-vous ?',action:'Recherchez un signe scientifique dans le Coran et approfondissez-le'}},
  {id:4,emoji:'📜',ar:{title:'القصص القرآني',desc:'قصص القرآن ليست للتسلية بل للعبرة والتعليم. كل قصة تحمل دروساً خالدة للبشرية.',insight:'القصص القرآني يقدم العبرة لا الخيال',reflection:'ما أكثر قصة قرآنية أثرت فيك؟',action:'اقرأ قصة نبي واستخرج منها ثلاث عبر عملية'},en:{title:'Quranic Narratives',desc:'Quranic stories are not for entertainment but for lessons and education. Each story carries eternal lessons for humanity.',insight:'Quranic narratives offer lessons, not fiction',reflection:'Which Quranic story has impacted you the most?',action:'Read a prophet\'s story and extract three practical lessons'},fr:{title:'Les Recits Coraniques',desc:"Les histoires du Coran ne sont pas pour le divertissement mais pour les lecons et l'education. Chaque histoire porte des lecons eternelles.",insight:'Les recits coraniques offrent des lecons, pas de la fiction',reflection:'Quelle histoire coranique vous a le plus impacte ?',action:"Lisez l'histoire d'un prophete et extrayez trois lecons pratiques"}},
  {id:5,emoji:'⚖️',ar:{title:'التشريع القرآني',desc:'التشريعات القرآنية جاءت لتحقيق العدالة والرحمة. الغزالي يوضح أن كل حكم قرآني له حكمة عظيمة وراءه.',insight:'التشريع القرآني يجمع بين العدل والرحمة',reflection:'هل تأملت في حكمة تشريع قرآني واحد؟',action:'اختر حكماً قرآنياً وابحث عن حكمته'},en:{title:'Quranic Legislation',desc:'Quranic legislation came to achieve justice and mercy. Al-Ghazali explains that every Quranic ruling has great wisdom behind it.',insight:'Quranic legislation combines justice and mercy',reflection:'Have you reflected on the wisdom of a single Quranic ruling?',action:'Choose a Quranic ruling and research its wisdom'},fr:{title:'La Legislation Coranique',desc:'La legislation coranique est venue pour realiser la justice et la misericorde. Al-Ghazali explique que chaque regle coranique a une grande sagesse derriere elle.',insight:'La legislation coranique allie justice et misericorde',reflection:"Avez-vous reflechi a la sagesse d'une seule regle coranique ?",action:'Choisissez une regle coranique et recherchez sa sagesse'}},
  {id:6,emoji:'💚',ar:{title:'الشفاء الروحي',desc:'القرآن شفاء للصدور والنفوس. الغزالي يرى أن كثيراً من أمراض القلوب علاجها في القرآن: القلق، الحزن، الخوف.',insight:'القرآن شفاء لما في الصدور — ليس مجازاً بل حقيقة',reflection:'متى آخر مرة شعرت بالسكينة من قراءة القرآن؟',action:'عندما تشعر بالقلق أو الحزن، افتح القرآن واقرأ'},en:{title:'Spiritual Healing',desc:'The Quran is healing for hearts and souls. Al-Ghazali believes many heart diseases find their cure in the Quran: anxiety, grief, fear.',insight:'The Quran is healing for what is in the hearts — not metaphor but reality',reflection:'When was the last time you felt peace from reading the Quran?',action:'When you feel anxious or sad, open the Quran and read'},fr:{title:'La Guerison Spirituelle',desc:"Le Coran est guerison pour les coeurs et les ames. Al-Ghazali croit que beaucoup de maladies du coeur trouvent leur remede dans le Coran.",insight:'Le Coran est guerison pour ce qui est dans les coeurs — pas une metaphore mais une realite',reflection:'Quand avez-vous ressenti la paix en lisant le Coran pour la derniere fois ?',action:'Quand vous vous sentez anxieux ou triste, ouvrez le Coran et lisez'}},
  {id:7,emoji:'🌍',ar:{title:'القرآن والحضارة',desc:'القرآن أسس حضارة امتدت من الأندلس إلى الصين. الغزالي يوضح كيف بنى القرآن حضارة العلم والعدل.',insight:'القرآن بنى أعظم حضارة عرفها التاريخ',reflection:'كيف يمكن للقرآن أن يبني حضارة اليوم؟',action:'اقرأ عن إنجاز حضاري إسلامي مستوحى من القرآن'},en:{title:'The Quran and Civilization',desc:'The Quran established a civilization that stretched from Andalusia to China. Al-Ghazali explains how the Quran built a civilization of knowledge and justice.',insight:'The Quran built the greatest civilization history has known',reflection:'How can the Quran build civilization today?',action:'Read about an Islamic civilizational achievement inspired by the Quran'},fr:{title:'Le Coran et la Civilisation',desc:"Le Coran a fonde une civilisation qui s'etendait de l'Andalousie a la Chine. Al-Ghazali explique comment le Coran a bati une civilisation de savoir et de justice.",insight:'Le Coran a bati la plus grande civilisation que l\'histoire ait connue',reflection:"Comment le Coran peut-il batir la civilisation aujourd'hui ?",action:'Lisez sur une reussite civilisationnelle islamique inspiree du Coran'}},
  {id:8,emoji:'🤲',ar:{title:'الدعاء في القرآن',desc:'القرآن مليء بالأدعية الجامعة التي علّمنا الله إياها. كل دعاء قرآني يحمل حكمة في صياغته ومعناه.',insight:'أدعية القرآن هي أفضل ما ندعو به — لأن الله هو من علّمنا إياها',reflection:'كم دعاءً قرآنياً تحفظ وتدعو به؟',action:'احفظ دعاءً قرآنياً جديداً اليوم وادعُ به'},en:{title:'Supplication in the Quran',desc:'The Quran is full of comprehensive supplications that God taught us. Each Quranic supplication carries wisdom in its wording and meaning.',insight:"Quranic supplications are the best we can pray with — because God Himself taught them to us",reflection:'How many Quranic supplications do you know and pray with?',action:'Memorize a new Quranic supplication today and pray with it'},fr:{title:'L\'Invocation dans le Coran',desc:"Le Coran est plein d'invocations completes que Dieu nous a enseignees. Chaque invocation coranique porte une sagesse dans sa formulation.",insight:'Les invocations coraniques sont les meilleures — car c\'est Dieu qui nous les a enseignees',reflection:'Combien d\'invocations coraniques connaissez-vous ?',action:"Memorisez une nouvelle invocation coranique aujourd'hui"}},
  {id:9,emoji:'🧭',ar:{title:'الأخلاق القرآنية',desc:'القرآن أسس منظومة أخلاقية شاملة: الصدق، الأمانة، العدل، الرحمة، الإحسان. هذه الأخلاق ليست نظرية بل عملية.',insight:'الأخلاق القرآنية منظومة عملية لا نظرية',reflection:'أي خلق قرآني تحتاج لتطويره في نفسك؟',action:'اختر خلقاً قرآنياً واحداً وطبقه اليوم بوعي'},en:{title:'Quranic Ethics',desc:'The Quran established a comprehensive ethical system: truthfulness, trustworthiness, justice, mercy, excellence. These ethics are practical, not theoretical.',insight:'Quranic ethics are a practical system, not theoretical',reflection:'Which Quranic virtue do you need to develop in yourself?',action:'Choose one Quranic virtue and consciously apply it today'},fr:{title:'L\'Ethique Coranique',desc:"Le Coran a etabli un systeme ethique complet : veracite, fiabilite, justice, misericorde, excellence. Ces valeurs sont pratiques, pas theoriques.",insight:"L'ethique coranique est un systeme pratique, pas theorique",reflection:'Quelle vertu coranique devez-vous developper en vous ?',action:"Choisissez une vertu coranique et appliquez-la consciemment aujourd'hui"}},
  {id:10,emoji:'🌙',ar:{title:'القرآن والعبادة',desc:'القرآن ليس فقط كتاباً يُقرأ بل هو عبادة في ذاته. قراءته تهذب النفس وتقرب من الله.',insight:'قراءة القرآن عبادة — كل حرف بحسنة والحسنة بعشر أمثالها',reflection:'كم وقتاً تخصص يومياً لقراءة القرآن؟',action:'خصص ١٠ دقائق يومياً لقراءة القرآن بتدبر'},en:{title:'The Quran and Worship',desc:'The Quran is not only a book to be read but an act of worship in itself. Reading it refines the soul and brings one closer to God.',insight:'Reading the Quran is worship — every letter earns a good deed multiplied by ten',reflection:'How much time do you dedicate daily to reading the Quran?',action:'Dedicate 10 minutes daily to reading the Quran with reflection'},fr:{title:'Le Coran et l\'Adoration',desc:"Le Coran n'est pas seulement un livre a lire mais un acte d'adoration en soi. Le lire raffine l'ame et rapproche de Dieu.",insight:"Lire le Coran est une adoration — chaque lettre vaut une bonne action multipliee par dix",reflection:'Combien de temps consacrez-vous quotidiennement a la lecture du Coran ?',action:'Consacrez 10 minutes par jour a la lecture du Coran avec reflexion'}},
  {id:11,emoji:'🔑',ar:{title:'مفاتيح التدبر',desc:'التدبر يحتاج لأدوات: معرفة أسباب النزول، فهم السياق، ربط الآيات ببعضها، والتأمل في المعنى.',insight:'التدبر ليس صعباً لكنه يحتاج ممارسة وصبراً',reflection:'هل تملك أداة واحدة للتدبر؟',action:'ابدأ بقراءة تفسير مختصر لسورة قصيرة'},en:{title:'Keys to Contemplation',desc:'Contemplation needs tools: knowing reasons of revelation, understanding context, connecting verses, and reflecting on meaning.',insight:'Contemplation is not difficult but needs practice and patience',reflection:'Do you have one tool for Quranic contemplation?',action:'Start by reading a brief commentary on a short surah'},fr:{title:'Les Cles de la Contemplation',desc:'La contemplation necessite des outils : connaitre les raisons de la revelation, comprendre le contexte, relier les versets et reflechir au sens.',insight:'La contemplation n\'est pas difficile mais necessite pratique et patience',reflection:'Avez-vous un outil pour la contemplation coranique ?',action:'Commencez par lire un bref commentaire d\'une courte sourate'}},
  {id:12,emoji:'🌅',ar:{title:'القرآن والطبيعة',desc:'القرآن يدعو للتأمل في الطبيعة كدليل على عظمة الخالق. السماوات والأرض والجبال والبحار كلها آيات.',insight:'الطبيعة كتاب مفتوح يقرأه من يتدبر القرآن',reflection:'متى آخر مرة تأملت في الطبيعة كآية من آيات الله؟',action:'اخرج اليوم وتأمل في مخلوقات الله من حولك'},en:{title:'The Quran and Nature',desc:'The Quran calls for contemplation of nature as evidence of the Creator\'s greatness. The heavens, earth, mountains, and seas are all signs.',insight:'Nature is an open book read by those who contemplate the Quran',reflection:'When was the last time you contemplated nature as a sign of God?',action:'Go outside today and contemplate God\'s creations around you'},fr:{title:'Le Coran et la Nature',desc:'Le Coran appelle a la contemplation de la nature comme preuve de la grandeur du Createur. Les cieux, la terre, les montagnes et les mers sont tous des signes.',insight:'La nature est un livre ouvert lu par ceux qui contemplent le Coran',reflection:'Quand avez-vous contemple la nature comme signe de Dieu pour la derniere fois ?',action:"Sortez aujourd'hui et contemplez les creations de Dieu autour de vous"}},
  {id:13,emoji:'📊',ar:{title:'تناسق القرآن',desc:'القرآن يتميز بتناسق مذهل بين سوره وآياته. لا تناقض ولا تكرار عبثي — كل شيء بحساب دقيق.',insight:'تناسق القرآن معجزة في حد ذاته',reflection:'هل لاحظت يوماً الترابط بين آيات سورة واحدة؟',action:'اقرأ سورة قصيرة وحاول اكتشاف الترابط بين آياتها'},en:{title:'Quranic Coherence',desc:'The Quran is distinguished by amazing coherence between its chapters and verses. No contradictions, no pointless repetition — everything is precisely calculated.',insight:'The coherence of the Quran is a miracle in itself',reflection:'Have you ever noticed the connection between verses of a single surah?',action:'Read a short surah and try to discover the connection between its verses'},fr:{title:'La Coherence Coranique',desc:'Le Coran se distingue par une coherence etonnante entre ses chapitres et ses versets. Pas de contradictions, pas de repetition inutile — tout est calcule avec precision.',insight:'La coherence du Coran est un miracle en soi',reflection:'Avez-vous deja remarque le lien entre les versets d\'une seule sourate ?',action:'Lisez une courte sourate et essayez de decouvrir le lien entre ses versets'}},
  {id:14,emoji:'💡',ar:{title:'القرآن والعقل',desc:'القرآن يخاطب العقل ويدعو للتفكير. "أفلا تعقلون" و"أفلا تتفكرون" تتكرر عشرات المرات.',insight:'القرآن يرفض التقليد الأعمى ويدعو للتفكير الحر',reflection:'هل تتأمل بعقلك أم تقلد بلا تفكير؟',action:'فكر في قضية واحدة اليوم باستقلالية'},en:{title:'The Quran and Reason',desc:'The Quran addresses reason and calls for thinking. "Will you not reason?" and "Will you not reflect?" are repeated dozens of times.',insight:'The Quran rejects blind imitation and calls for free thinking',reflection:'Do you reflect with your mind or follow without thinking?',action:'Think independently about one issue today'},fr:{title:'Le Coran et la Raison',desc:'Le Coran s\'adresse a la raison et appelle a la reflexion. "Ne raisonnez-vous pas ?" et "Ne reflechissez-vous pas ?" sont repetes des dizaines de fois.',insight:'Le Coran rejette l\'imitation aveugle et appelle a la pensee libre',reflection:'Reflechissez-vous avec votre esprit ou suivez-vous sans penser ?',action:"Pensez de maniere independante a une question aujourd'hui"}},
  {id:15,emoji:'🕊️',ar:{title:'القرآن والسلام',desc:'القرآن دين السلام. "يا أيها الذين آمنوا ادخلوا في السلم كافة". الإسلام يدعو للسلام مع النفس ومع الآخرين.',insight:'السلام في القرآن يبدأ من الداخل ثم ينتشر للخارج',reflection:'هل أنت في سلام مع نفسك ومع من حولك؟',action:'سامح شخصاً اليوم واصنع سلاماً في قلبك'},en:{title:'The Quran and Peace',desc:'The Quran is the religion of peace. "O you who believe, enter into peace completely." Islam calls for peace with oneself and with others.',insight:'Peace in the Quran starts from within then spreads outward',reflection:'Are you at peace with yourself and those around you?',action:'Forgive someone today and create peace in your heart'},fr:{title:'Le Coran et la Paix',desc:'Le Coran est la religion de la paix. "O vous qui croyez, entrez dans la paix completement." L\'Islam appelle a la paix avec soi-meme et avec les autres.',insight:'La paix dans le Coran commence de l\'interieur puis se repand a l\'exterieur',reflection:'Etes-vous en paix avec vous-meme et ceux qui vous entourent ?',action:"Pardonnez a quelqu'un aujourd'hui et creez la paix dans votre coeur"}},
  {id:16,emoji:'⏳',ar:{title:'القرآن والتاريخ',desc:'القرآن يقدم رؤية فريدة للتاريخ. ليس تاريخاً خطياً بل دروس تتكرر. سنن الله في الأمم لا تتغير.',insight:'التاريخ في القرآن يقدم سنناً ثابتة لا أحداثاً عابرة',reflection:'ما الدرس التاريخي القرآني الأكثر صلة بواقعنا اليوم؟',action:'اقرأ قصة أمة في القرآن واستخرج سنة إلهية منها'},en:{title:'The Quran and History',desc:'The Quran offers a unique view of history. Not linear history but repeating lessons. God\'s patterns in nations do not change.',insight:'History in the Quran presents fixed patterns, not passing events',reflection:'What Quranic historical lesson is most relevant to our reality today?',action:'Read the story of a nation in the Quran and extract a divine pattern'},fr:{title:'Le Coran et l\'Histoire',desc:'Le Coran offre une vision unique de l\'histoire. Pas une histoire lineaire mais des lecons qui se repetent. Les lois de Dieu dans les nations ne changent pas.',insight:'L\'histoire dans le Coran presente des modeles fixes, pas des evenements passagers',reflection:'Quelle lecon historique coranique est la plus pertinente aujourd\'hui ?',action:'Lisez l\'histoire d\'une nation dans le Coran et extrayez un modele divin'}},
  {id:17,emoji:'🌱',ar:{title:'القرآن والتربية',desc:'القرآن يربي الإنسان تربية شاملة: عقلية، روحية، اجتماعية، وأخلاقية. منهج تربوي متكامل.',insight:'القرآن أعظم كتاب تربية في التاريخ',reflection:'كيف يمكنك استخدام القرآن في تربية نفسك وأبنائك؟',action:'اختر آية تربوية وطبقها مع أسرتك اليوم'},en:{title:'The Quran and Education',desc:'The Quran educates holistically: intellectually, spiritually, socially, and morally. A comprehensive educational methodology.',insight:'The Quran is the greatest educational book in history',reflection:'How can you use the Quran in educating yourself and your children?',action:'Choose an educational verse and apply it with your family today'},fr:{title:'Le Coran et l\'Education',desc:"Le Coran eduque de maniere holistique : intellectuellement, spirituellement, socialement et moralement. Une methodologie educative complete.",insight:'Le Coran est le plus grand livre d\'education de l\'histoire',reflection:'Comment pouvez-vous utiliser le Coran pour eduquer vous-meme et vos enfants ?',action:"Choisissez un verset educatif et appliquez-le avec votre famille aujourd'hui"}},
  {id:18,emoji:'🌐',ar:{title:'القرآن للعالمين',desc:'القرآن ليس للمسلمين فقط بل للبشرية جمعاء. "وما أرسلناك إلا رحمة للعالمين". رسالته عالمية.',insight:'عالمية القرآن من أبرز خصائصه',reflection:'كيف يمكنك مشاركة حكمة القرآن مع غير المسلمين؟',action:'شارك قيمة قرآنية عالمية مع شخص من ثقافة مختلفة'},en:{title:'The Quran for All Mankind',desc:'The Quran is not for Muslims only but for all humanity. "We have not sent you except as a mercy to the worlds." Its message is universal.',insight:'The universality of the Quran is among its most prominent features',reflection:'How can you share Quranic wisdom with non-Muslims?',action:'Share a universal Quranic value with someone from a different culture'},fr:{title:'Le Coran pour Toute l\'Humanite',desc:"Le Coran n'est pas seulement pour les musulmans mais pour toute l'humanite. Nous ne t'avons envoye que comme misericorde pour les mondes. Son message est universel.",insight:'L\'universalite du Coran est parmi ses caracteristiques les plus marquantes',reflection:'Comment pouvez-vous partager la sagesse coranique avec les non-musulmans ?',action:'Partagez une valeur coranique universelle avec quelqu\'un d\'une autre culture'}},
  {id:19,emoji:'🔐',ar:{title:'حفظ القرآن',desc:'الله تكفل بحفظ القرآن. "إنا نحن نزلنا الذكر وإنا له لحافظون". لم يتغير حرف واحد منذ ١٤٠٠ سنة.',insight:'حفظ القرآن معجزة مستمرة عبر القرون',reflection:'ما دورك في حفظ القرآن ونشره؟',action:'احفظ آية جديدة اليوم أو راجع ما تحفظه'},en:{title:'Preservation of the Quran',desc:'God guaranteed the preservation of the Quran. "Indeed, it is We who sent down the reminder, and indeed, We will be its guardian." Not a single letter has changed in 1,400 years.',insight:'The preservation of the Quran is an ongoing miracle across centuries',reflection:'What is your role in preserving and spreading the Quran?',action:'Memorize a new verse today or review what you have memorized'},fr:{title:'La Preservation du Coran',desc:"Dieu a garanti la preservation du Coran. C'est Nous qui avons fait descendre le Rappel et c'est Nous qui en sommes les Gardiens. Pas une seule lettre n'a change en 1400 ans.",insight:'La preservation du Coran est un miracle continu a travers les siecles',reflection:'Quel est votre role dans la preservation et la diffusion du Coran ?',action:"Memorisez un nouveau verset aujourd'hui ou revisez ce que vous avez memorise"}},
  {id:20,emoji:'🌟',ar:{title:'القرآن: نور لا ينطفئ',desc:'الغزالي يختم بأن القرآن نور دائم لا ينطفئ. كلما ازداد العلم ازداد القرآن إعجازاً. هو كتاب لكل زمان ومكان.',insight:'القرآن يتجدد مع كل جيل ولا يشيخ أبداً',reflection:'ما أكثر شيء يعجبك في القرآن؟',action:'شارك هذا التطبيق مع شخص يحب القرآن'},en:{title:'The Quran: A Light That Never Fades',desc:'Al-Ghazali concludes that the Quran is a permanent light that never fades. The more knowledge advances, the more miraculous the Quran becomes. It is a book for all times and places.',insight:'The Quran renews with every generation and never ages',reflection:'What do you admire most about the Quran?',action:'Share this app with someone who loves the Quran'},fr:{title:'Le Coran : Une Lumiere qui ne s\'Eteint Jamais',desc:"Al-Ghazali conclut que le Coran est une lumiere permanente qui ne s'eteint jamais. Plus la science avance, plus le Coran devient miraculeux. C'est un livre pour tous les temps et tous les lieux.",insight:'Le Coran se renouvelle avec chaque generation et ne vieillit jamais',reflection:'Qu\'admirez-vous le plus dans le Coran ?',action:'Partagez cette application avec quelqu\'un qui aime le Coran'}}
];

