document.addEventListener('DOMContentLoaded',()=>{setTheme(theme);setLang(lang);initSplash();initTabs();initScrollTop();initTicker();renderHome();renderConcepts();renderMiracles();renderHabits();renderQuiz();renderAbout();renderHelp();renderDuas();initScrollReveal();initKeyboardNav();});

function initSplash(){let count=5;const el=document.getElementById('splashCount');const fe=document.getElementById('splashFeatures');if(fe)fe.innerHTML=T[lang].splashFeatures.map((f,i)=>`<div class="splash-feature" style="animation-delay:${0.3+i*0.3}s">${f}</div>`).join('');const iv=setInterval(()=>{count--;if(el)el.textContent=count;if(count<=0){dismissSplash();clearInterval(iv);}},1000);}
function dismissSplash(){const s=document.getElementById('splash');if(s){s.classList.add('hidden');setTimeout(()=>s.style.display='none',500);}playSound('click');}

function setLang(l){lang=l;localStorage.setItem('nq-lang',l);const isRTL=l==='ar';document.documentElement.lang=l;document.documentElement.dir=isRTL?'rtl':'ltr';document.body.dir=isRTL?'rtl':'ltr';document.querySelectorAll('.lang-opt').forEach(b=>b.classList.toggle('active',b.dataset.lang===l));const t=T[l];const set=(id,val)=>{const el=document.getElementById(id);if(el)el.textContent=val;};set('appTitle',t.appTitle);set('splashSub',t.splashSub);set('splashHint',t.splashHint);set('tabHome',t.tabHome);set('tabConcepts',t.tabConcepts);set('tabMiracles',t.tabMiracles);set('tabHabits',t.tabHabits);set('tabQuiz',t.tabQuiz);set('tabAbout',t.tabAbout);set('conceptsTitle',t.conceptsTitle);set('conceptsDesc',t.conceptsDesc);set('miraclesTitle',t.miraclesTitle);set('miraclesDesc',t.miraclesDesc);set('habitsTitle',t.habitsTitle);set('habitsDesc',t.habitsDesc);set('quizTitle',t.quizTitle);set('quizDesc',t.quizDesc);set('helpTitle',t.helpTitle);set('duaPanelTitle',t.duaPanelTitle);set('habitsReset',t.resetBtn);renderHome();renderConcepts();renderMiracles();renderHabits();renderQuiz();renderAbout();renderHelp();renderDuas();const fe=document.getElementById('splashFeatures');if(fe)fe.innerHTML=T[l].splashFeatures.map((f,i)=>`<div class="splash-feature" style="animation-delay:${0.3+i*0.3}s">${f}</div>`).join('');}

function setTheme(t){theme=t;document.documentElement.dataset.theme=t;localStorage.setItem('nq-theme',t);const idx=themes.indexOf(t);const el=document.getElementById('themeIcon');if(el)el.textContent=themeIcons[idx];}
function cycleTheme(){const idx=(themes.indexOf(theme)+1)%themes.length;setTheme(themes[idx]);showToast(themeNames[themes[idx]]);playSound('theme');}

function initTabs(){document.querySelectorAll('.tab').forEach(tab=>{tab.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));tab.classList.add('active');const panel=document.getElementById('panel-'+tab.dataset.tab);if(panel)panel.classList.add('active');window.scrollTo({top:0,behavior:'smooth'});playSound('click');});});}

function initTicker(){const el=document.getElementById('tickerText');if(!el)return;const msgs={ar:['📖 نظرات في القرآن — الشيخ محمد الغزالي','✨ ٢٠ تأمل في كتاب الله','🔬 إعجاز القرآن: بلاغي وعلمي وتشريعي'],en:['📖 Insights into the Quran — Sheikh al-Ghazali','✨ 20 reflections on God\'s Book','🔬 Quranic miracles: literary, scientific, legislative'],fr:['📖 Regards sur le Coran — Sheikh al-Ghazali','✨ 20 reflexions sur le Livre de Dieu','🔬 Miracles coraniques : litteraires, scientifiques, legislatifs']};const items=(msgs[lang]||msgs.en).map(m=>`<span class="tc">&nbsp;&nbsp;&nbsp;${m}&nbsp;&nbsp;&nbsp;</span>`).join('');el.innerHTML=items+items;el.style.animation=`tickerMarquee ${(msgs[lang]||msgs.en).length*12}s linear infinite`;}

function renderHome(){const t=T[lang];const dayIdx=new Date().getDate()%CONCEPTS.length;const c=CONCEPTS[dayIdx][lang];document.getElementById('dailyCard').innerHTML=`<div class="daily-label">${t.dailyLabel}</div><div class="daily-title">${c.title}</div><div class="daily-body">${c.desc}</div><div class="daily-action" onclick="document.querySelector('[data-tab=concepts]').click()">${t.tabConcepts} &#8594;</div>`;const sections=[{icon:'📖',tab:'concepts',title:t.tabConcepts,desc:lang==='ar'?'٢٠ تأمل':lang==='fr'?'20 reflexions':'20 reflections'},{icon:'✨',tab:'miracles',title:t.tabMiracles,desc:lang==='ar'?'جوانب الإعجاز':lang==='fr'?'Aspects des miracles':'Aspects of miracles'},{icon:'📋',tab:'habits',title:t.tabHabits,desc:lang==='ar'?'عادات قرآنية':lang==='fr'?'Habitudes coraniques':'Quranic habits'},{icon:'🤔',tab:'quiz',title:t.tabQuiz,desc:lang==='ar'?'اختبر نفسك':lang==='fr'?'Testez-vous':'Test yourself'},{icon:'📖',tab:'about',title:t.tabAbout,desc:lang==='ar'?'عن الكتاب':lang==='fr'?'Le livre':'The book'}];document.getElementById('homeGrid').innerHTML=sections.map(s=>`<div class="home-card" onclick="document.querySelector('[data-tab=${s.tab}]').click()"><span class="hc-icon">${s.icon}</span><div class="hc-title">${s.title}</div><div class="hc-desc">${s.desc}</div></div>`).join('');}

function renderConcepts(){const t=T[lang];const searchBar=`<div class="search-bar"><input type="text" id="conceptsSearch" class="search-input" placeholder="${t.searchPlaceholder}" oninput="filterConcepts(this.value)"><span class="search-icon">🔍</span></div>`;const cards=CONCEPTS.map((c,i)=>{const d=c[lang];return`<div class="principle-card scroll-reveal" id="concept-${c.id}" data-search="${d.title.toLowerCase()}"><div class="principle-head" onclick="toggleCard('concept-${c.id}')"><span class="principle-num">${c.id}</span><span class="principle-emoji">${c.emoji}</span><span class="principle-title">${d.title}</span><span class="principle-chev">&#9660;</span></div><div class="principle-body"><div class="principle-inner"><p class="principle-desc">${d.desc}</p><div class="comparison-box"><div class="comparison-side carnegie-side"><div class="comp-label">${t.insight}</div><div class="comp-text">${d.insight}</div></div><div class="comparison-side ghazali-side"><div class="comp-label">${t.reflection}</div><div class="comp-text">${d.reflection}</div></div></div><div class="action-box"><span class="action-icon">💡</span><span>${d.action}</span></div><button class="share-btn" onclick="event.stopPropagation();shareConcept(${i})"><span class="share-icon">&#128279;</span> ${t.share}</button></div></div></div>`;}).join('');document.getElementById('conceptsContainer').innerHTML=searchBar+cards;}
function filterConcepts(q){q=q.toLowerCase().trim();document.querySelectorAll('.principle-card').forEach(card=>{const s=card.dataset.search||'';const t=card.querySelector('.principle-title');const tt=t?t.textContent.toLowerCase():'';card.style.display=(!q||s.includes(q)||tt.includes(q))?'':'none';});}
async function shareConcept(idx){const c=CONCEPTS[idx],d=c[lang];const text=`${c.emoji} ${d.title}\n\n${d.desc}\n\n💡 ${d.action}\n\n— نظرات في القرآن`;if(navigator.share){try{await navigator.share({title:d.title,text});}catch(e){}}else{try{await navigator.clipboard.writeText(text);showToast(lang==='ar'?'تم النسخ!':lang==='fr'?'Copie !':'Copied!');}catch(e){showToast('Could not copy');}}}

function renderMiracles(){document.getElementById('miraclesContainer').innerHTML=MIRACLES.map(m=>{const d=m[lang];return`<div class="anxiety-card scroll-reveal"><div class="anxiety-header"><span class="anxiety-emoji">${m.emoji}</span><span class="anxiety-title">${d.name}</span></div><div class="anxiety-problem" style="border-color:var(--primary)"><span class="anxiety-label" style="color:var(--primary)">${d.aspect}</span></div><div class="anxiety-solution"><span class="anxiety-label" style="color:var(--accent)">${d.detail}</span></div></div>`;}).join('');}

function renderHabits(){const today=new Date().toDateString();let hs=JSON.parse(localStorage.getItem('nq-habits')||'{}');if(hs.date!==today){updateStreak(hs);hs={date:today,done:[]};localStorage.setItem('nq-habits',JSON.stringify(hs));}const streak=getStreak();const streakHTML=streak>0?`<div class="streak-badge">🔥 ${streak} ${T[lang].streakMsg}</div>`:'';document.getElementById('habitsContainer').innerHTML=HABITS.map((h,i)=>{const d=h[lang];const isDone=hs.done.includes(i);return`<div class="habit-item ${isDone?'done':''}" onclick="toggleHabit(${i})"><span class="habit-check">${isDone?'&#10003;':''}</span><span class="habit-emoji">${h.emoji}</span><div><div class="habit-label">${d.label}</div><div class="habit-source">${d.source}</div></div></div>`;}).join('');const se=document.getElementById('streakBadge');if(se)se.innerHTML=streakHTML;updateHabitsProgress(hs);}
function toggleHabit(i){const today=new Date().toDateString();let hs=JSON.parse(localStorage.getItem('nq-habits')||'{}');if(hs.date!==today)hs={date:today,done:[]};const idx=hs.done.indexOf(i);if(idx>-1)hs.done.splice(idx,1);else hs.done.push(i);localStorage.setItem('nq-habits',JSON.stringify(hs));renderHabits();playSound(idx>-1?'click':'success');if(hs.done.length===HABITS.length){launchConfetti();showToast(T[lang].allDone);}}
function resetHabits(){localStorage.setItem('nq-habits',JSON.stringify({date:new Date().toDateString(),done:[]}));renderHabits();showToast(lang==='ar'?'تم إعادة التعيين':lang==='fr'?'Reinitialise':'Reset');}
function updateHabitsProgress(hs){const d=hs.done.length,t=HABITS.length,p=t>0?(d/t*100):0;const f=document.getElementById('habitsFill'),tx=document.getElementById('habitsText');if(f)f.style.width=p+'%';if(tx)tx.textContent=`${d}/${t}`;}
function updateStreak(ps){let sd=JSON.parse(localStorage.getItem('nq-streak')||'{"count":0,"lastDate":""}');if(ps&&ps.done&&ps.done.length===HABITS.length&&ps.date){const y=new Date();y.setDate(y.getDate()-1);if(ps.date===y.toDateString())sd.count++;else if(ps.date!==new Date().toDateString())sd.count=ps.done.length===HABITS.length?1:0;sd.lastDate=ps.date;}else if(ps&&ps.date){sd.count=0;sd.lastDate=ps.date;}localStorage.setItem('nq-streak',JSON.stringify(sd));}
function getStreak(){return JSON.parse(localStorage.getItem('nq-streak')||'{"count":0}').count;}

function launchConfetti(){const canvas=document.getElementById('confettiCanvas');if(!canvas)return;canvas.style.display='block';const ctx=canvas.getContext('2d');canvas.width=window.innerWidth;canvas.height=window.innerHeight;const particles=[];const colors=['#0D47A1','#1565C0','#42A5F5','#66BB6A','#FFD54F','#E91E63','#4FC3F7'];for(let i=0;i<120;i++)particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height-canvas.height,w:Math.random()*10+5,h:Math.random()*6+3,color:colors[Math.floor(Math.random()*colors.length)],vx:(Math.random()-0.5)*4,vy:Math.random()*3+2,rot:Math.random()*360,rotSpeed:(Math.random()-0.5)*10});let frame=0;function draw(){ctx.clearRect(0,0,canvas.width,canvas.height);particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.rot+=p.rotSpeed;ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rot*Math.PI/180);ctx.fillStyle=p.color;ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);ctx.restore();});frame++;if(frame<120)requestAnimationFrame(draw);else{ctx.clearRect(0,0,canvas.width,canvas.height);canvas.style.display='none';}}draw();}

function renderQuiz(){const t=T[lang];document.getElementById('quizContainer').innerHTML=QUIZ.map((q,i)=>`<div class="quiz-question scroll-reveal" id="quiz-q-${i}"><div class="quiz-q-text">${i+1}. ${q[lang]}</div><div class="quiz-options"><button class="quiz-opt" onclick="selectQuizOpt(${i},2)">${lang==='ar'?'نعم':lang==='fr'?'Oui':'Yes'}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},1)">${lang==='ar'?'أحياناً':lang==='fr'?'Parfois':'Sometimes'}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},0)">${lang==='ar'?'لا':lang==='fr'?'Non':'No'}</button></div></div>`).join('')+`<button class="quiz-submit" onclick="submitQuiz()">${t.submitQuiz}</button>`;document.getElementById('quizResult').classList.add('hidden');window._quizAnswers={};}
function selectQuizOpt(qi,val){window._quizAnswers[qi]=val;document.querySelectorAll(`#quiz-q-${qi} .quiz-opt`).forEach((o,oi)=>o.classList.toggle('selected',[2,1,0][oi]===val));playSound('click');}
function submitQuiz(){const answers=window._quizAnswers||{};if(Object.keys(answers).length<QUIZ.length){showToast(lang==='ar'?'أجب على جميع الأسئلة':lang==='fr'?'Repondez a toutes les questions':'Answer all questions');return;}let score=0;Object.values(answers).forEach(v=>{score+=v;});const max=QUIZ.length*2,pct=Math.round(score/max*100);let emoji,title,desc;if(pct>=75){emoji='🌟';title=lang==='ar'?'ممتاز!':lang==='fr'?'Excellent !':'Excellent!';desc=lang==='ar'?'معرفتك بالقرآن رائعة! استمر في التدبر.':lang==='fr'?'Votre connaissance du Coran est remarquable !':'Your knowledge of the Quran is remarkable!';}else if(pct>=50){emoji='📖';title=lang==='ar'?'جيد':lang==='fr'?'Bien':'Good';desc=lang==='ar'?'لديك معرفة جيدة. تابع القراءة والتدبر.':lang==='fr'?'Vous avez de bonnes connaissances. Continuez a lire.':'You have good knowledge. Keep reading and reflecting.';}else{emoji='🔍';title=lang==='ar'?'حان وقت التدبر':lang==='fr'?'Temps de reflechir':'Time to Reflect';desc=lang==='ar'?'ابدأ بقراءة القرآن يومياً بتدبر.':lang==='fr'?'Commencez par lire le Coran quotidiennement avec reflexion.':'Start reading the Quran daily with reflection.';}const result=document.getElementById('quizResult');result.classList.remove('hidden');result.innerHTML=`<div class="qr-emoji">${emoji}</div><div class="qr-score">${pct}%</div><div class="qr-title">${title}</div><div class="qr-desc">${desc}</div><button class="quiz-submit" onclick="renderQuiz()" style="margin-top:16px">${T[lang].quizAgain}</button>`;result.scrollIntoView({behavior:'smooth'});playSound('success');}

function renderAbout(){const about={ar:{disclaimerTitle:'⚠️ تنبيه مهم',disclaimer:'لست عالماً. هذا جهد متواضع لنشر تأملات الشيخ الغزالي في القرآن.',authorName:'الشيخ محمد الغزالي',authorDates:'١٩١٧ — ١٩٩٦',authorBio:'عالم ومفكر إسلامي مصري. ألّف أكثر من ٩٤ كتاباً. عُرف بعمق فهمه للقرآن وبلاغة أسلوبه. درّس في جامعة الأمير عبد القادر بقسنطينة (الجزائر).',bookTitle:'عن الكتاب',bookDesc:'"نظرات في القرآن" — يقدم الغزالي تأملات عميقة في كتاب الله، موضحاً جوانب الإعجاز البلاغي والعلمي والتشريعي، مع التأكيد على أن القرآن منهج حياة شامل وليس كتاباً للتبرك فقط.',sourcesTitle:'المصادر',sources:['كتاب "نظرات في القرآن" — الشيخ محمد الغزالي','القرآن الكريم'],contact:'تواصل: abdelhak.bourdim@gmail.com'},en:{disclaimerTitle:'⚠️ Important Notice',disclaimer:"I am not a scholar. This is a humble effort to share Sheikh al-Ghazali's Quranic reflections.",authorName:'Sheikh Mohammed al-Ghazali',authorDates:'1917 — 1996',authorBio:'Egyptian Islamic scholar and thinker. Author of 94+ books. Known for his deep understanding of the Quran. Taught at University of Emir Abdelkader in Constantine, Algeria.',bookTitle:'About the Book',bookDesc:'"Insights into the Quran" — Al-Ghazali offers deep reflections on God\'s Book, explaining literary, scientific, and legislative miracles, emphasizing the Quran is a comprehensive way of life.',sourcesTitle:'Sources',sources:['"Insights into the Quran" — Sheikh Mohammed al-Ghazali','The Holy Quran'],contact:'Contact: abdelhak.bourdim@gmail.com'},fr:{disclaimerTitle:'⚠️ Avis Important',disclaimer:"Je ne suis ni savant. C'est un effort humble pour partager les reflexions coraniques du Sheikh al-Ghazali.",authorName:'Sheikh Mohammed al-Ghazali',authorDates:'1917 — 1996',authorBio:"Savant et penseur islamique egyptien. Auteur de plus de 94 livres. Connu pour sa profonde comprehension du Coran. Professeur a l'Universite Emir Abdelkader de Constantine (Algerie).",bookTitle:'A Propos du Livre',bookDesc:'"Regards sur le Coran" — Al-Ghazali offre des reflexions profondes sur le Livre de Dieu, expliquant les miracles litteraires, scientifiques et legislatifs.',sourcesTitle:'Sources',sources:['"Regards sur le Coran" — Sheikh Mohammed al-Ghazali','Le Saint Coran'],contact:'Contact : abdelhak.bourdim@gmail.com'}};const a=about[lang];document.getElementById('aboutContainer').innerHTML=`<div class="about-disclaimer"><div class="about-disclaimer-title">${a.disclaimerTitle}</div><p>${a.disclaimer}</p></div><div class="about-author"><span class="about-author-icon">📚</span><div class="about-author-info"><div class="about-author-name">${a.authorName}</div><div class="about-author-dates">${a.authorDates}</div><div class="about-author-bio">${a.authorBio}</div></div></div><div class="about-section"><div class="about-section-title">${a.bookTitle}</div><p class="about-text">${a.bookDesc}</p></div><div class="about-section"><div class="about-section-title">${a.sourcesTitle}</div>${a.sources.map(s=>`<p class="about-text">&#8226; ${s}</p>`).join('')}</div><div class="about-section"><p class="about-text">${a.contact}</p></div>`;}

function renderHelp(){const help={ar:[{title:'⚠️ تنبيه',body:'لست عالماً. هذا جهد متواضع لنشر تأملات الشيخ الغزالي في القرآن.'},{title:'📚 المصادر',body:'كتاب "نظرات في القرآن" للشيخ محمد الغزالي.'},{title:'✨ المميزات',body:'ثلاث لغات، ٣ أنماط، ٢٠ نظرة، إعجاز القرآن، عادات قرآنية، اختبار، أدعية.'}],en:[{title:'⚠️ Disclaimer',body:"I am not a scholar. This is a humble effort to share Sheikh al-Ghazali's Quranic reflections."},{title:'📚 Sources',body:'"Insights into the Quran" by Sheikh Mohammed al-Ghazali.'},{title:'✨ Features',body:'Three languages, 3 themes, 20 insights, Quranic miracles, habits, quiz, duas.'}],fr:[{title:'⚠️ Avertissement',body:"Je ne suis pas un savant. C'est un effort humble."},{title:'📚 Sources',body:'"Regards sur le Coran" par Sheikh Mohammed al-Ghazali.'},{title:'✨ Fonctionnalites',body:'Trois langues, 3 themes, 20 regards, miracles coraniques, habitudes, quiz, duas.'}]};document.getElementById('helpBody').innerHTML=help[lang].map(h=>`<div class="help-item"><div class="help-item-title">${h.title}</div><div>${h.body}</div></div>`).join('');}

function renderDuas(){document.getElementById('duaPanelContent').innerHTML=DUAS.map(d=>{const dd=d[lang];return`<div class="dua-item"><div class="dua-item-label">${dd.label}</div><div class="dua-item-ar">${dd.text}</div><div class="dua-item-tr">${dd.tr}</div></div>`;}).join('');}

function initScrollReveal(){if(!('IntersectionObserver' in window))return;const o=new IntersectionObserver((entries)=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('revealed');o.unobserve(e.target);}});},{threshold:0.08,rootMargin:'0px 0px -40px 0px'});function obs(){document.querySelectorAll('.scroll-reveal:not(.revealed)').forEach(el=>o.observe(el));}obs();document.querySelectorAll('.tab').forEach(t=>{t.addEventListener('click',()=>setTimeout(obs,100));});}

function initKeyboardNav(){document.addEventListener('keydown',(e)=>{if(e.key==='Escape'){const hp=document.getElementById('helpPanel');if(!hp.classList.contains('hidden')){toggleHelp();return;}const dp=document.getElementById('duaPanel');if(!dp.classList.contains('hidden')){toggleDuaPanel();return;}document.querySelectorAll('.principle-card.open').forEach(c=>c.classList.remove('open'));}if(e.key==='ArrowRight'||e.key==='ArrowLeft'){const panel=document.getElementById('panel-concepts');if(!panel||!panel.classList.contains('active'))return;if(document.activeElement&&document.activeElement.id==='conceptsSearch')return;e.preventDefault();const cards=Array.from(document.querySelectorAll('.principle-card')).filter(c=>c.style.display!=='none');if(!cards.length)return;if(currentConceptIdx>=0&&currentConceptIdx<cards.length)cards[currentConceptIdx].classList.remove('open');const dir=(document.documentElement.dir==='rtl')?(e.key==='ArrowRight'?-1:1):(e.key==='ArrowRight'?1:-1);currentConceptIdx=Math.max(0,Math.min(cards.length-1,currentConceptIdx+dir));cards[currentConceptIdx].classList.add('open');cards[currentConceptIdx].scrollIntoView({behavior:'smooth',block:'center'});playSound('click');}});}

function toggleCard(id){const card=document.getElementById(id);if(card){card.classList.toggle('open');playSound('click');}}
function toggleHelp(){document.getElementById('helpPanel').classList.toggle('hidden');playSound('click');}
function toggleDuaPanel(){document.getElementById('duaPanel').classList.toggle('hidden');playSound('click');}
function showToast(msg){const t=document.getElementById('toast'),m=document.getElementById('toastMsg');if(t&&m){m.textContent=msg;t.style.display='block';setTimeout(()=>t.style.display='none',2500);}}
function initScrollTop(){const btn=document.getElementById('scrollTop');window.addEventListener('scroll',()=>{if(btn)btn.classList.toggle('visible',window.scrollY>300);});}

const AudioCtx=window.AudioContext||window.webkitAudioContext;let audioCtx;
function playSound(type){try{if(!audioCtx)audioCtx=new AudioCtx();const osc=audioCtx.createOscillator(),gain=audioCtx.createGain();osc.connect(gain);gain.connect(audioCtx.destination);gain.gain.value=0.06;if(type==='click'){osc.frequency.value=800;osc.type='sine';gain.gain.value=0.04;}else if(type==='success'){osc.frequency.value=523;osc.type='sine';}else if(type==='theme'){osc.frequency.value=440;osc.type='triangle';gain.gain.value=0.05;}osc.start();osc.stop(audioCtx.currentTime+0.1);}catch(e){}}
